  ('judicial-57112235-moex-00077', 'judicial-57112235', 'judicial-57112235-moex-114-b098244d', 'sub-judicial-57112235-03', NULL, 'essay', '監獄暴行之種類，大致可分為幾種？暴行發生之原因為何？及預防措施
有那些？請詳加說明之。（每小題 5 分，共 15分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "83a7e2e69390", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "監獄學概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00078', 'judicial-57112235', 'judicial-57112235-moex-114-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '長刑期受刑人受到長期監禁的負面影響，在生活適應上經常面臨到諸多挑戰。因此學者 Mitchell 提出了幾項做法，將有助於長刑期受刑人之生活適應。有關學者Mitchell之論點，下列何者錯誤？', '["將長刑期受刑人視為獨特之團體，並與其他類型之受刑人分區管理", "對長刑期受刑人之戒護分類應具彈性", "提供長期刑受刑人之生活指導與方向", "以充分運用監獄資源為目標之生涯計畫"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "83a7e2e69390", "answer_pdf_sha1": "9529cae49e00", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00079', 'judicial-57112235', 'judicial-57112235-moex-114-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關我國假釋與善時制度（GoodTimeSystem）之敘述，下列何者正確？', '["相異點：假釋有執行一定刑期之限制；善時制度則無執行一定刑期之限制", "相同點：兩者皆適用於累進處遇三級以上之受刑人", "相異點：假釋以行政處分救濟長期自由刑；善時制度則無救濟方式", "相同點：假釋受刑人與因善時制度提前出獄之受刑人，均應交付保護管束"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "83a7e2e69390", "answer_pdf_sha1": "9529cae49e00", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00080', 'judicial-57112235', 'judicial-57112235-moex-114-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '矯正人員（CorrectionalOfficers）已被公認是專業工作者，為維護矯正人員專業形象及地位，矯正 人員有其應遵守的專業倫理，有關專業倫理守則之敘述，下列何者錯誤？', '["矯正人員應共同維護職業尊嚴，不得於收容人面前批評長官或同仁，亦不得發表有損機關聲譽 之言論", "矯正人員要自我期許，以身作則，作為收容人的表率；不能利用職務之便為媒介或營利行為", "矯正人員因收容人性別取向、宗教信仰或社經地位之不同，而有歧視收容人之行為，得依規定 予以懲處", "矯正人員積極結合社會各界資源，得接受並運用收容人親友贈送之禮物，以強化收容人教化及 矯正之效果 20620"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "83a7e2e69390", "answer_pdf_sha1": "9529cae49e00", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00081', 'judicial-57112235', 'judicial-57112235-moex-114-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '依美國學者N.M.Cochranc調查研究發現有關脫逃者的特徵，下列敘述何者錯誤？', '["攻擊性之人格", "習慣犯", "40歲至50歲最多", "不合作態度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "83a7e2e69390", "answer_pdf_sha1": "9529cae49e00", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00082', 'judicial-57112235', 'judicial-57112235-moex-114-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關我國監獄調查分類制度及規定，下列敘述何者錯誤？', '["調查分類目的之一在於有效擬定處遇計畫，進行考核觀察及輔導", "新入監受刑人之個性、身心狀況、經歷、教育程度等，均為調查項目", "新入監受刑人之調查期間上限為1個月", "受刑人入監後要在3個月內，訂定其個別處遇計畫，並適時修正"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "83a7e2e69390", "answer_pdf_sha1": "9529cae49e00", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00083', 'judicial-57112235', 'judicial-57112235-moex-114-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '收容人在服刑期間自殺，屬於戒護事故的一種。學者Danto對收容人自殺之動機及成因，將自殺 收容人區分為四種類型，關於此四種類型之敘述，下列何者正確？', '["長期絕望型：由於羈押前後社會角色的巨大落差，使其在絕望之心理壓力自殺", "工具型：視自殺為降低罪惡感的方式之一", "自我懲罰型：此類型自殺者通常具有反社會人格特質，其真意並非自殺，而是引起管理員之重視", "道德衝擊型：此類型的收容人於犯罪前的特色通常是循規蹈矩、擁有正常之家庭生活且無明顯 犯罪前科的人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "83a7e2e69390", "answer_pdf_sha1": "9529cae49e00", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00084', 'judicial-57112235', 'judicial-57112235-moex-114-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關監獄作業制度之描述，下列何者正確？', '["租賃制：監獄將受刑人租於廠商到監外，由監獄負責管教人員之俸給，廠方負責受刑人之衣食、 住所、紀律與戒護管理", "公用制：由監獄主動派受刑人到監外從事建築、浚河、造林及其他富有公益價值等工作的作業型態", "代工制：廠商與監獄簽訂契約，監獄負責受刑人之衣食、住所、紀律與戒護管理，廠商負責成 品之運銷販售", "自營制：由監獄自己經營，盈虧自負，不得與其他民間企業自由競爭，成品銷售僅限於公家機 關與政府部門所資助之公益團體"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "83a7e2e69390", "answer_pdf_sha1": "9529cae49e00", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00085', 'judicial-57112235', 'judicial-57112235-moex-114-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '認知處遇法（CognitiveApproachofOffenderRehabilitation），在矯正機關教化實務上被認為具有一 定之成效，下列何者不是認知處遇法的主要實施方式？', '["偏誤思考的導正訓練", "社交技巧及人際溝通的訓練", "解析夢境，分析潛意識之衝動", "憤怒情緒之管理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "83a7e2e69390", "answer_pdf_sha1": "9529cae49e00", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00086', 'judicial-57112235', 'judicial-57112235-moex-114-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關矯正機關舍房勤務，下列何者錯誤？', '["舍房交接班應清點人數，注意房內人數與房外收容人名牌是否相符", "收容人出房作業或收封入房，舍房主管人員逐一查點人數", "收容人夜間的各種狀況，請視同作業收容人協助記載於勤務簿", "舍房主管應熟悉舍房區域的消防設施及緊急出口處"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "83a7e2e69390", "answer_pdf_sha1": "9529cae49e00", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
